CREATE TABLE drone_tracks (
  id BIGSERIAL PRIMARY KEY,
  timestamp TIMESTAMPTZ,
  sensor_id INT,
  geom GEOMETRY(PointZ, 4326),
  velocity_ms FLOAT,
  heading_deg FLOAT,
  class TEXT,
  confidence FLOAT
);
CREATE INDEX idx_tracks_time ON drone_tracks (timestamp DESC);
CREATE INDEX idx_tracks_geom ON drone_tracks USING GIST (geom);

