class PursuitNode(Node):
    def __init__(self):
        super().__init__('pursuit')
        self.track_sub = self.create_subscription(PoseStamped, '/target_track', self.cb, 10)
        self.vel_pub = self.create_publisher(TwistStamped, '/mavros/setpoint_velocity/cmd_vel', 10)

    def cb(self, msg):
        # Proportional navigation
        los = compute_los(self_pos, msg.pose.position)
        cmd = proportional_nav(los, self_vel, target_vel, N=3)
        self.vel_pub.publish(cmd)
